#include "controller.h"

/* Track the safe actuator state - when was the last time we were in a safe zone? */
static controller_state_t s_last_safe_state = CONTROLLER_STATE_SAFE_OFF;
static int s_last_safe_temperature_c = 0;

static void controller_set_safe_off(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

