        if (controller->has_valid_sensor && controller->last_valid_sensor_ms > 0) {
            uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
            if (elapsed_ms >= CONTROLLER_SENSOR_TIMEOUT_MS) {
                /* Timeout detected - fail safe */
                controller_set_safe_off(controller);
                output.heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_OFF;
                output.state_name = "STATE SAFE_OFF";
                output.changed = true;
                return output;
            }
        }

        /* No new input, keep previous state */
        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = false;
        return output;
    }

    /* Process valid temperature input */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Apply control policy based on current temperature */
        int32_t prev_temp = controller->last_temperature_c;
        bool temp_rising = (input.temperature_c > prev_temp);

        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* TEMP < 47: heat up */
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
            /* Don't record safe state when heating - we're not in a safe zone yet */
        } else if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* TEMP > 52: fail safe off */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_SAFE_OFF;
            /* Record the safe state */
            controller_record_safe_state(controller);
        } else if (input.temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* 47 <= TEMP < 50: hold previous safe actuator state */
            /* The "previous safe actuator state" is what we were in when last in safe zone */
            controller->heater_on = s_last_safe_state == CONTROLLER_STATE_SAFE_OFF ? false : true;
            controller->state = CONTROLLER_STATE_HOLDING;
        } else if (input.temperature_c >= CONTROLLER_TEMP_HIGH_THRESHOLD && input.temperature_c <= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* This case handles 50 <= TEMP <= 52 */
            if (temp_rising) {
                /* Temperature is rising - turn heater off early, HOLDING state */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
                /* Record the safe state since we're now in a safe zone */
                controller_record_safe_state(controller);
            } else {
                /* Temperature not rising - hold previous safe actuator state */
                controller->heater_on = s_last_safe_state == CONTROLLER_STATE_SAFE_OFF ? false : true;
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        }

        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
        return output;
    }

    /* Default case - should not reach here */
    output.heater_on = false;
    output.state = CONTROLLER_STATE_SAFE_OFF;
    output.state_name = "STATE SAFE_OFF";
    output.changed = true;
    return output;
}

